export interface IconProps {
  name: IconName;
  size?: IconSize;
  color?: string;
  "aria-label"?: string;
  "aria-hidden"?: boolean;
  style?: React.CSSProperties;
  className?: string;
}

export function Icon({
  name,
  size = 16,
  color = "currentColor",
  "aria-label": ariaLabel,
  "aria-hidden": ariaHidden = !ariaLabel,
  style,
  className,
}: IconProps) {
  const map = size === 24 ? ICONS_24 : ICONS_16;
  const viewBox = size === 24 ? "0 0 24 24" : "0 0 16 16";
  const content = map[name] ?? null;

  return (
    <svg
      width={size}
      height={size}
      viewBox={viewBox}
      fill="none"
      style={{ color, display: "block", flexShrink: 0, ...style }}
      aria-label={ariaLabel}
      aria-hidden={ariaHidden}
      className={className}
    >
      {content ? (
        <g dangerouslySetInnerHTML={{ __html: content }} />
      ) : (
        <rect
          x={size === 24 ? 4 : 2}
          y={size === 24 ? 4 : 2}
          width={size === 24 ? 16 : 12}
          height={size === 24 ? 16 : 12}
          rx="2"
          stroke={color}
          strokeDasharray="3 2"
          fill="none"
        />
      )}
    </svg>
  );
}
